import React from "react";
import SpinningText from "../SpinningText";
import GotMilk from "../images/foto.png";
import WorkspacePremiumIcon from "@mui/icons-material/WorkspacePremium";
import { skillGroups, certifications } from "../../contentV2";
import Reveal from "./Reveal";

// Importamos explícitamente ambos archivos desde src
import cvEspanol from "../CV_Viqui_Alaro_ES.pdf";
import cvIngles from "../CV_Viqui_Alaro_EN.pdf";

export default function AboutV2({ t, lang }) {
  // Evaluamos de forma estricta si el idioma actual es inglés ('en')
  const isEnglish = lang === "en" || lang === "English" || lang === "EN";
  
  const curriculumUrl = isEnglish ? cvIngles : cvEspanol;
  const fileName = isEnglish ? "CV_Viqui_Alaro_EN.pdf" : "CV_Viqui_Alaro_ES.pdf";

  return (
    <section id="about" className="v2-about">
      
      {/* --- FONDO ANIMADO --- */}
      <div className="area" aria-hidden="true">
        <ul className="circles">
          <li></li><li></li><li></li><li></li><li></li>
          <li></li><li></li><li></li><li></li><li></li>
        </ul>
      </div>

      <div style={{ position: "relative", zIndex: 1 }}>
        <Reveal width="100%">
          <div className="v2-section-head">
            <h2>{t.about.title}</h2>
            <span className="v2-rule" />
          </div>
        </Reveal>

        <Reveal width="100%">
          <div className="v2-about-grid">
            <div className="v2-about-left">
              <SpinningText text={t.about.spin}>
                <img src={GotMilk} alt="Foto de perfil de Viqui Alaro" />
              </SpinningText>

              {/* Enlace dinámico que cambia según el estado de 'lang' */}
              <a 
                href={curriculumUrl} 
                download={fileName} 
                className="v2-btn v2-btn-sm"
                style={{ textDecoration: "none", display: "inline-block", textAlign: "center" }}
              >
                ⬇ {t.about.cv}
              </a>

              <div className="v2-badges">
                {certifications.map((c) => (
                  <div className="v2-badge" key={c.label}>
                    <WorkspacePremiumIcon fontSize="large" />
                    <span>{c.label}</span>
                  </div>
                ))}
              </div>
            </div>

            <div className="v2-about-right">
              <p>{t.about.p1}</p>
              <p>{t.about.p2}</p>

              {skillGroups.map((group) => (
                <div className="v2-skill-group" key={group.key}>
                  <h3>{group.label[lang]}</h3>
                  <div className="v2-chips">
                    {group.items.map((item) => (
                      <span className="v2-chip" key={item}>
                        {item}
                      </span>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </Reveal>
      </div>
    </section>
  );
}